import { useEffect, useState } from "react"

const Usefetch=()=>{
    const [Data,setData] =useState([])
    useEffect(()=>{
        console.log("STARTED")
        fetch("http://localhost:8000/TaskUploads")
        .then(res =>{
            console.log('Fetchin..')
            return res.json();
        })
        .then(data=>{
            setData(data)
            console.log(data)
        })
        .catch((err) => console.log(err));
    },[])
    return{Data}
}

export default  Usefetch;
